    dialects:{egy:[{ar:"لَيْلَى بِتِصْحَى السَّاعَة سِتَّة الصُّبْح كُلّ يَوْم.",en:"Layla wakes up at 6am every day.",eg:"لَيْلَى بِتِصْحَى السَّاعَة سِتَّة الصُّبْح كُلّ يَوْم.",lev:"لَيْلَى بِتِصْحَى السَّاعَة سِتَّة الصُّبْح كُلّ يَوْم.",gulf:"لَيْلَى بِتِصْحَى السَّاعَة سِتَّة الصُّبْح كُلّ يَوْم."},{ar:"الأَوِّل بِتِصَلِّي الفَجْر وَبَعْدِين بِتِشْرَب أَهْوَة.",en:"First she prays Fajr then drinks coffee.",eg:"الأَوِّل بِتِصَلِّي الفَجْر وَبَعْدِين بِتِشْرَب أَهْوَة.",lev:"الأَوِّل بِتِصَلِّي الفَجْر وَبَعْدِين بِتِشْرَب أَهْوَة.",gulf:"الأَوِّل بِتِصَلِّي الفَجْر وَبَعْدِين بِتِشْرَب أَهْوَة."},{ar:"بِتِرُوح الجَامِعَة بِالأُتُوبِيس.",en:"She goes to university by bus.",eg:"بِتِرُوح الجَامِعَة بِالأُتُوبِيس.",lev:"بِتِرُوح الجَامِعَة بِالأُتُوبِيس.",gulf:"بِتِرُوح الجَامِعَة بِالأُتُوبِيس."}],lev:[{ar:"لَيْلَى بِتِصْحَى السَّاعَة سِتَّة الصُّبْح كُلّ يَوْم.",en:"Layla wakes up at 6am every day.",eg:"لَيْلَى بِتِصْحَى السَّاعَة سِتَّة الصُّبْح كُلّ يَوْم.",lev:"لَيْلَى بِتِصْحَى السَّاعَة سِتَّة الصُّبْح كُلّ يَوْم.",gulf:"لَيْلَى بِتِصْحَى السَّاعَة سِتَّة الصُّبْح كُلّ يَوْم."},{ar:"أَوَّل شِي بِتِصَلِّي الفَجْر وَبَعْدِين بِتِشْرَب أَهْوَة.",en:"First she prays Fajr then drinks coffee.",eg:"أَوَّل شِي بِتِصَلِّي الفَجْر وَبَعْدِين بِتِشْرَب أَهْوَة.",lev:"أَوَّل شِي بِتِصَلِّي الفَجْر وَبَعْدِين بِتِشْرَب أَهْوَة.",gulf:"أَوَّل شِي بِتِصَلِّي الفَجْر وَبَعْدِين بِتِشْرَب أَهْوَة."},{ar:"بِتْرُوح عَالجَامِعَة بِالبَاص.",en:"She goes to university by bus.",eg:"بِتْرُوح عَالجَامِعَة بِالبَاص.",lev:"بِتْرُوح عَالجَامِعَة بِالبَاص.",gulf:"بِتْرُوح عَالجَامِعَة بِالبَاص."}],gulf:[{ar:"لَيْلَى تِصَحَّى السَّاعَة سِتَّة الصُّبْح كُلّ يَوْم.",en:"Layla wakes up at 6am every day.",eg:"لَيْلَى تِصَحَّى السَّاعَة سِتَّة الصُّبْح كُلّ يَوْم.",lev:"لَيْلَى تِصَحَّى السَّاعَة سِتَّة الصُّبْح كُلّ يَوْم.",gulf:"لَيْلَى تِصَحَّى السَّاعَة سِتَّة الصُّبْح كُلّ يَوْم."},{ar:"أَوَّل شَي تُصَلِّي الفَجْر وَبَعْدَيْن تِشْرَب قَهْوَة.",en:"First she prays Fajr then drinks coffee.",eg:"أَوَّل شَي تُصَلِّي الفَجْر وَبَعْدَيْن تِشْرَب قَهْوَة.",lev:"أَوَّل شَي تُصَلِّي الفَجْر وَبَعْدَيْن تِشْرَب قَهْوَة.",gulf:"أَوَّل شَي تُصَلِّي الفَجْر وَبَعْدَيْن تِشْرَب قَهْوَة."},{ar:"تِرُوح الجَامِعَة بِالباص.",en:"She goes to university by bus.",eg:"تِرُوح الجَامِعَة بِالباص.",lev:"تِرُوح الجَامِعَة بِالباص.",gulf:"تِرُوح الجَامِعَة بِالباص."}]},
