    dialects:{egy:[{ar:"بَيْتَنَا كِبِير وَمِرِيح — فِيهِ تَلَات أُوَض وَصَالُون.",en:"Our house is big and comfortable — it has 3 rooms and a living room.",eg:"بَيْتَنَا كِبِير وَمِرِيح — فِيهِ تَلَات أُوَض وَصَالُون.",lev:"بَيْتَنَا كِبِير وَمِرِيح — فِيهِ تَلَات أُوَض وَصَالُون.",gulf:"بَيْتَنَا كِبِير وَمِرِيح — فِيهِ تَلَات أُوَض وَصَالُون."},{ar:"أُمِّي بِتِحِبّ المَطْبَخ وَبِتِطْبُخ كُلّ يَوْم.",en:"My mother loves the kitchen and cooks every day.",eg:"أُمِّي بِتِحِبّ المَطْبَخ وَبِتِطْبُخ كُلّ يَوْم.",lev:"أُمِّي بِتِحِبّ المَطْبَخ وَبِتِطْبُخ كُلّ يَوْم.",gulf:"أُمِّي بِتِحِبّ المَطْبَخ وَبِتِطْبُخ كُلّ يَوْم."},{ar:"أَحْسَن حَاجَة هِيَ البَلَكُونَة — بِقْعُد هِنَاك وَبِقْرَأ.",en:"The best thing is the balcony — I sit there and read.",eg:"أَحْسَن حَاجَة هِيَ البَلَكُونَة — بِقْعُد هِنَاك وَبِقْرَأ.",lev:"أَحْسَن حَاجَة هِيَ البَلَكُونَة — بِقْعُد هِنَاك وَبِقْرَأ.",gulf:"أَحْسَن حَاجَة هِيَ البَلَكُونَة — بِقْعُد هِنَاك وَبِقْرَأ."}],lev:[{ar:"بَيْتَنَا كَبِير وَمِرِيح — فِيهِ تْلَت أُوَض وَصَالُون.",en:"Our house is big and comfortable — it has 3 rooms and a living room.",eg:"بَيْتَنَا كَبِير وَمِرِيح — فِيهِ تْلَت أُوَض وَصَالُون.",lev:"بَيْتَنَا كَبِير وَمِرِيح — فِيهِ تْلَت أُوَض وَصَالُون.",gulf:"بَيْتَنَا كَبِير وَمِرِيح — فِيهِ تْلَت أُوَض وَصَالُون."},{ar:"إِمِّي بِتْحِبّ المَطْبَخ وَعَم بِتْطْبُخ كُلّ يَوْم.",en:"My mother loves the kitchen and is cooking every day.",eg:"إِمِّي بِتْحِبّ المَطْبَخ وَعَم بِتْطْبُخ كُلّ يَوْم.",lev:"إِمِّي بِتْحِبّ المَطْبَخ وَعَم بِتْطْبُخ كُلّ يَوْم.",gulf:"إِمِّي بِتْحِبّ المَطْبَخ وَعَم بِتْطْبُخ كُلّ يَوْم."},{ar:"أَحْسَن مَكَان هُوَ البَلْكُون — بِقْعُد هَوْنِيك وَبِقْرَأ.",en:"The best place is the balcony — I sit there and read.",eg:"أَحْسَن مَكَان هُوَ البَلْكُون — بِقْعُد هَوْنِيك وَبِقْرَأ.",lev:"أَحْسَن مَكَان هُوَ البَلْكُون — بِقْعُد هَوْنِيك وَبِقْرَأ.",gulf:"أَحْسَن مَكَان هُوَ البَلْكُون — بِقْعُد هَوْنِيك وَبِقْرَأ."}],gulf:[{ar:"بَيْتَنَا كَبِير وَمِرِيح — فِيهِ ثَلَاث غُرَف وَصَالَة.",en:"Our house is big and comfortable — it has 3 rooms and a living room.",eg:"بَيْتَنَا كَبِير وَمِرِيح — فِيهِ ثَلَاث غُرَف وَصَالَة.",lev:"بَيْتَنَا كَبِير وَمِرِيح — فِيهِ ثَلَاث غُرَف وَصَالَة.",gulf:"بَيْتَنَا كَبِير وَمِرِيح — فِيهِ ثَلَاث غُرَف وَصَالَة."},{ar:"أُمِّي تِحِبّ المَطْبَخ وَتِطْبُخ كُلّ يَوْم.",en:"My mother loves the kitchen and cooks every day.",eg:"أُمِّي تِحِبّ المَطْبَخ وَتِطْبُخ كُلّ يَوْم.",lev:"أُمِّي تِحِبّ المَطْبَخ وَتِطْبُخ كُلّ يَوْم.",gulf:"أُمِّي تِحِبّ المَطْبَخ وَتِطْبُخ كُلّ يَوْم."},{ar:"أَحْسَن مَكَان هِيَ البَرَنْدَة — أَقْعُد هِنَاك وَأَقْرَأ.",en:"The best place is the balcony — I sit there and read.",eg:"أَحْسَن مَكَان هِيَ البَرَنْدَة — أَقْعُد هِنَاك وَأَقْرَأ.",lev:"أَحْسَن مَكَان هِيَ البَرَنْدَة — أَقْعُد هِنَاك وَأَقْرَأ.",gulf:"أَحْسَن مَكَان هِيَ البَرَنْدَة — أَقْعُد هِنَاك وَأَقْرَأ."}]},
