    comprehension:[
  {type:"mcq",q:"What does دَائِماً mean?",opts:["Sometimes","Never","Always","Rarely"],ans:2,exp:"دَائِماً = always. The frequency adverbs: دَائِماً (always) → عَادَةً (usually) → أَحْيَاناً (sometimes) → نَادِراً (rarely) → أَبَداً (never)."},
  {type:"tf",q:"لَمْ + present indicative negates a past action.",ans:1,exp:"FALSE — لَمْ + JUSSIVE (not indicative) negates past actions. لَمْ يَذْهَبْ = he did not go. The jussive drops the final ـُ."},
  {type:"mcq",q:"What does إِن شَاءَ اللهُ express culturally?",opts:["A command","Acknowledgment that God controls the future","A past event","A negative statement"],ans:1,exp:"إِن شَاءَ اللهُ = If God wills it — acknowledging that the future is in God's hands. Essential cultural expression in Arab speech."},
  {type:"mcq",q:"In verb-subject order (VSO), the verb agrees with the subject in...",opts:["Number only","Gender only","Both gender AND number","Neither"],ans:1,exp:"When the verb comes BEFORE the subject, it agrees only in GENDER (not number). بَاعَت النِّسَاءُ (the women sold) — verb is feminine singular."}
,
      {type:"fitb",q:"When the verb comes BEFORE its plural subject, it is _____",blank:"singular",opts:["singular","plural","dual","depends on gender"],exp:"VSO order: the verb stays singular but must match the subject's gender."},
      {type:"mcq",q:"Non-human plurals take which form of verb/adjective agreement?",opts:["Masculine plural","Feminine plural","Feminine singular","Masculine singular"],ans:2,exp:"Non-human plurals (books, cars, etc.) are treated as feminine singular in Arabic."}],
