    comprehension:[
  {type:"mcq",q:"What is طَرَب best described as?",opts:["A type of food","Musical/emotional ecstasy unique to Arabic","A formal greeting","A grammar term"],ans:1,exp:"طَرَب = a uniquely Arabic concept of musical and emotional ecstasy felt when deeply moved by music — has no direct English equivalent."},
  {type:"tf",q:"مُشْتَاق and مُشْتَاقَة mean the same thing.",ans:1,exp:"FALSE — مُشْتَاق (masculine) and مُشْتَاقَة (feminine) both mean 'missing someone / longing for' but differ in grammatical gender."},
  {type:"mcq",q:"To say 'I feel happy' in Arabic, which preposition follows أَشْعُر?",opts:["فِي","مِن","بِـ","إِلَى"],ans:2,exp:"أَشْعُر بِـ + noun = I feel. The ب is required: أَشْعُر بِالسَّعَادَة (I feel happiness). Cannot say أَشْعُر السَّعَادَة."},
  {type:"mcq",q:"Which emotion is described as 'longing for an absent person'?",opts:["فَرَح","حُزْن","شَوْق","خَوْف"],ans:2,exp:"شَوْق = longing/yearning for someone absent. Related to اِشْتِيَاق and مُشْتَاق. A deeply romantic and poetic concept in Arabic."}
,
      {type:"fitb",q:"_____ تَذهَبِي إِلَى السُّوق أَمسِ. (You-f. did not go)",blank:"لَمْ",opts:["لَمْ","لَا","مَا"],exp:"لَمْ + مَجزُوم = past negation. لَمْ تَذهَبِي = You (f.) did not go."},
      {type:"mcq",q:"Which particle negates the past tense in formal Arabic?",opts:["لَا","مَا","لَمْ","لَنْ"],ans:2,exp:"لَمْ + مُضَارِع مَجزُوم = past negation. Colloquially مَا + ماضٍ is also used."}],
