    dialects:{egy:[{ar:"العَرَبِيّ لُغَة غَنِيَّة — كُلّ كَلِمَة لَيْهَا جَذْر.",en:"Arabic is a rich language — every word has a root.",eg:"العَرَبِيّ لُغَة غَنِيَّة — كُلّ كَلِمَة لَيْهَا جَذْر.",lev:"العَرَبِيّ لُغَة غَنِيَّة — كُلّ كَلِمَة لَيْهَا جَذْر.",gulf:"العَرَبِيّ لُغَة غَنِيَّة — كُلّ كَلِمَة لَيْهَا جَذْر."},{ar:"لَازِم تِقْرَا وَتِكْتِب وَتِسْمَع كُلّ يَوْم.",en:"You must read, write, and listen every day.",eg:"لَازِم تِقْرَا وَتِكْتِب وَتِسْمَع كُلّ يَوْم.",lev:"لَازِم تِقْرَا وَتِكْتِب وَتِسْمَع كُلّ يَوْم.",gulf:"لَازِم تِقْرَا وَتِكْتِب وَتِسْمَع كُلّ يَوْم."},{ar:"الصَّبْر مِفْتَاح الفَرَج — ماشِي!",en:"Patience is the key to relief — keep going!",eg:"الصَّبْر مِفْتَاح الفَرَج — ماشِي!",lev:"الصَّبْر مِفْتَاح الفَرَج — ماشِي!",gulf:"الصَّبْر مِفْتَاح الفَرَج — ماشِي!"}],lev:[{ar:"العَرَبِيَّة لُغَة غَنِيَّة — كُلّ كَلِمِة إِلِهَا جَذْر.",en:"Arabic is a rich language — every word has a root.",eg:"العَرَبِيَّة لُغَة غَنِيَّة — كُلّ كَلِمِة إِلِهَا جَذْر.",lev:"العَرَبِيَّة لُغَة غَنِيَّة — كُلّ كَلِمِة إِلِهَا جَذْر.",gulf:"العَرَبِيَّة لُغَة غَنِيَّة — كُلّ كَلِمِة إِلِهَا جَذْر."},{ar:"لَازِم تِقْرَأ وَتِكْتُب وَتِسْمَع كُلّ يَوْم.",en:"You must read, write, and listen every day.",eg:"لَازِم تِقْرَأ وَتِكْتُب وَتِسْمَع كُلّ يَوْم.",lev:"لَازِم تِقْرَأ وَتِكْتُب وَتِسْمَع كُلّ يَوْم.",gulf:"لَازِم تِقْرَأ وَتِكْتُب وَتِسْمَع كُلّ يَوْم."},{ar:"الصَّبْر مِفْتَاح الفَرَج — يَلَّا!",en:"Patience is the key to relief — let's go!",eg:"الصَّبْر مِفْتَاح الفَرَج — يَلَّا!",lev:"الصَّبْر مِفْتَاح الفَرَج — يَلَّا!",gulf:"الصَّبْر مِفْتَاح الفَرَج — يَلَّا!"}],gulf:[{ar:"العَرَبِيَّة لُغَة غَنِيَّة — كُلّ كَلِمَة إِلِهَا جَذْر.",en:"Arabic is a rich language — every word has a root.",eg:"العَرَبِيَّة لُغَة غَنِيَّة — كُلّ كَلِمَة إِلِهَا جَذْر.",lev:"العَرَبِيَّة لُغَة غَنِيَّة — كُلّ كَلِمَة إِلِهَا جَذْر.",gulf:"العَرَبِيَّة لُغَة غَنِيَّة — كُلّ كَلِمَة إِلِهَا جَذْر."},{ar:"لَازِم تِقْرَأ وَتِكْتِب وَتِسْمَع كُلّ يَوْم.",en:"You must read, write, and listen every day.",eg:"لَازِم تِقْرَأ وَتِكْتِب وَتِسْمَع كُلّ يَوْم.",lev:"لَازِم تِقْرَأ وَتِكْتِب وَتِسْمَع كُلّ يَوْم.",gulf:"لَازِم تِقْرَأ وَتِكْتِب وَتِسْمَع كُلّ يَوْم."},{ar:"الصَّبْر مِفْتَاح الفَرَج — يَالَّا!",en:"Patience is the key to relief — let's go!",eg:"الصَّبْر مِفْتَاح الفَرَج — يَالَّا!",lev:"الصَّبْر مِفْتَاح الفَرَج — يَالَّا!",gulf:"الصَّبْر مِفْتَاح الفَرَج — يَالَّا!"}]},
    comprehension:[
  {type:"mcq",q:"What is the feminine form of the colour أَحْمَر (red)?",opts:["أَحْمَرَة","أَحْمَارَة","حَمْرَاء","حَمْرَاءَة"],ans:2,exp:"حَمْرَاء = red (feminine). Colour adjectives follow أَفْعَل (m) / فَعْلَاء (f): أَزْرَق/زَرْقَاء (blue), أَبْيَض/بَيْضَاء (white)."},
  {type:"tf",q:"Colour adjectives in Arabic take normal tanwīn endings.",ans:1,exp:"FALSE — colour adjectives are DIPTOTES (ممنوع من الصرف): no tanwīn and they use -a in genitive/accusative. This is because they follow the أَفْعَل pattern."},
  {type:"mcq",q:"What does the traditional Gulf garment دِشْدَاشَة look like?",opts:["A long cloak covering the head","A long flowing white robe","A short colourful jacket","A striped headscarf"],ans:1,exp:"الدِّشْدَاشَة / الثَّوْب = a long flowing robe, typically white in the Gulf, worn by men. White reflects heat in the desert climate."},
  {type:"mcq",q:"If a dress (فُسْتَان) is blue, which form of blue is correct?",opts:["أَزْرَقَة","زَرْقَاء","أَزَارِيق","زُرَق"],ans:1,exp:"زَرْقَاء — feminine of أَزْرَق. فُسْتَان is masculine in Arabic, but the colour agrees with the noun's gender: فُسْتَان أَزْرَق. For a feminine noun (مَلَابِس): زَرْقَاء."}
,
      {type:"fitb",q:"أَحمَر — أَبيَض — أَخضَر. What morphological pattern is this?",blank:"أَفعَل",opts:["أَفعَل","فَاعِل","مَفعُول"],exp:"أَفعَل / فَعلَاء is the pattern for colour and defect adjectives in Arabic."},
      {type:"mcq",q:"What is the feminine form of أَسوَد (black)?",opts:["سَودَاء","أَسوَدَة","سَودَة","أَسوَدِيَّة"],ans:0,exp:"Colours: masculine = أَفعَل, feminine = فَعلَاء. أَسوَد → سَودَاء."}],
