      {ar:"الأَوَّل / الأَخِير",tr:"al-awwal / al-akhiir",en:"the first / the last (ordinals)",eg:"الأَوَّلاني / الأَخَراني",lev:"الأَوَّلاني / الأَخَراني",gulf:"الأَوَّل / الأَخِير"},
      {ar:"ضِعْف / مَرَّتَيْن",tr:"diif / marratayni",en:"double / twice (multiplication)",eg:"ضِعف / مَرَّتَيْن",lev:"ضِعف / مَرَّتَيْن",gulf:"ضِعف / مَرَّتَيْن"}
