    comprehension:[
  {type:"mcq",q:"سَأَحْجِز means...",opts:["I booked (past)","I am booking (present)","I will book (future)","Book for me (imperative)"],ans:2,exp:"سَـ + present tense = near future. سَأَحْجِز = I will book (soon). سَوْفَ is more emphatic and distant future. Both precede the present tense verb."},
  {type:"tf",q:"لَن + indicative expresses future negation.",ans:1,exp:"FALSE — لَن + SUBJUNCTIVE expresses future negation. لَن أَتَأَخَّرَ = I will not be late (subjunctive: يَتَأَخَّرَ → أَتَأَخَّرَ with fatḥa ending)."},
  {type:"mcq",q:"What does مُزْدَوَجَة mean in hotel vocabulary?",opts:["Single room","Double room","Suite","Dormitory"],ans:1,exp:"مُزْدَوَجَة = double (room). مُفْرَدَة = single. جَنَاح = suite. The root ز-و-ج (pair/couple) makes مُزْدَوَج = paired/double."},
  {type:"mcq",q:"هَل الفَطُور مَشْمُول؟ is asking...",opts:["Is there a restaurant?","Is breakfast included?","What time is checkout?","Is the room available?"],ans:1,exp:"مَشْمُول = included (passive participle of شَمَلَ). الفَطُور = breakfast. So: Is breakfast included? هَل الإِيجَار يَشْمَل الفَطُور؟ = Does the rent include breakfast?"}
,
      {type:"fitb",q:"أَنَا _____ أَزُورُ الأُردُنَّ السَّنَةَ القَادِمَة. (near future prefix)",blank:"سَـ",opts:["سَـ","سَوفَ","لَن"],exp:"سَـ (prefixed directly) = near future. سَوفَ is slightly more emphatic."},
      {type:"mcq",q:"Which particle negates the future tense?",opts:["لَمْ","لَا","لَنْ","مَا"],ans:2,exp:"لَنْ + subjunctive = will not (future negation)."}],
    grammar:[{
      title:"The Future Tense — سَـ and سَوْف",
      type:"table",
      headers:["Marker","Use","Example","Translation"],
      rows:[
        ["سَـ (prefix)","near future","سَأَحْجِز غُرْفَة","I will book a room"],
        ["سَوْفَ (separate)","emphatic future","سَوْفَ أَصِل غَدًا","I WILL arrive tomorrow"],
        ["لَنْ + subjunctive","future negation","لَن أَتَأَخَّرَ","I will NOT be late"],
        ["هَل + سَـ","future question","هَل سَتَحْجِز؟","Will you book?"]
      ],
      note:"Future: attach سَـ before the present tense: يَحْجِز → سَيَحْجِز (he will book). سَوْفَ is more emphatic. Negation: لَنْ + subjunctive (fatha on last letter, ـون drops ن). ★ FUTURE DRILL: Convert to future: يَذْهَبُ، تَكْتُبُ، نَدْرُسُ، يَلْعَبُون، تُسَافِرِين — using both سَـ and سَوْف. ★ FILL-IN: هِيَ ___ تُسَافِر إِلَى الأُرْدُن غَدًا. (use سَـ)"
    }],
