    reading:[
      {readingMeta:true,title:"المَنْسَفُ — فَخْرُ الأُرْدُنّ وَأُمُّ سَمِيرَة",type:"descriptive",preRead:"Every culture has a dish that means more than food — it means home, family, and identity. What is that dish for you? For Jordanians, it is mansaf.",focusWords:["المَنْسَف","الجَمِيد","اللَّبَن","الأَرُزّ","الكَرَم"]},
      {paraBreak:true,label:"قِصَّةُ الطَّبَق"},
      {ar:"المَنْسَفُ لَيْسَ مُجَرَّدَ طَعَامٍ — هُوَ طَقْسٌ اجْتِمَاعِيٌّ وَقَصِيدَةٌ فِي الكَرَم الأُرْدُنِيّ.",en:"Mansaf is not merely food — it is a social ritual and a poem in Jordanian generosity.",eg:"المَنْسَف مُشّ بَسِ أَكْل — هُوَ طَقْس اجْتِمَاعِيّ وَقَصِيدَة فِي الكَرَم الأُرْدُنِيّ.",lev:"المَنْسَف مُشّ بَسِ أَكِل — هُوَ طَقْس اجْتِمَاعِيّ وَقَصِيدَة بِالكَرَم الأُرْدُنِيّ.",gulf:"المَنْسَف مُشّ بَسِ أَكِل — هُوَ طَقْس اجْتِمَاعِيّ وَقَصِيدَة بِالكَرَم الأُرْدُنِيّ."},
      {ar:"يُصْنَعُ مِن لَحْمِ الخَرُوفِ المَطْبُوخِ فِي لَبَنِ الجَمِيد — وَيُقَدَّمُ فَوْقَ أَرُزٍّ بِالسَّمْنِ وَاللَّوْز المُحَمَّر.",en:"It is made from lamb cooked in dried fermented yoghurt — and served over rice with ghee and toasted almonds.",eg:"بِيتِعْمَل مِن لَحْمَة الخَرُوف المَطْبُوخَة فِي لَبَن الجَمِيد — وَبِيتِقَدِّم عَلَى أَرُزّ بِالسَّمْن وَاللَّوْز المُحَمِّر.",lev:"بِيتِعْمَل مِن لَحْمَة الخَرُوف المَطْبُوخَة بِلَبَن الجَمِيد — وَبِيتِقَدَّم فَوْق أَرُزّ بِالسَّمْن وَاللَّوْز المُحَمَّر.",gulf:"يِتِعْمَل مِن لَحْمَة الخَرُوف المَطْبُوخَة بِلَبَن الجَمِيد — وَيِتِقَدَّم فَوْق أَرُزّ بِالسَّمْن وَاللَّوْز المُحَمَّر."},
      {ar:"يَأْكُلُهُ الجَمِيعُ وَاقِفِينَ حَوْلَ صَيْنِيَّةٍ كَبِيرَة — اليَدُ الأَيْمَن فَقَط، وَالأَكْلُ بِالمَقْلُوب.",en:"Everyone eats it standing around a large tray — right hand only, and eating from the outside in.",eg:"الكُلّ بِيَاكُلُه وَاقِفِين حَوَالِين صِينِيَّة كِبِيرَة — اليَد اليُمْنَى بَسِ، وَالأَكِل بِالمَقْلُوب.",lev:"الكُلّ بِيَاكُلُه وَاقِفِين حَوَالِين صِينِيَّة كَبِيرَة — اليَد اليُمْنَى بَسِ، وَالأَكِل مِن الطَّرَف لِلمَركِز.",gulf:"الكُلّ يَاكُلُه وَاقِفِين حَوَالِين صِينِيَّة كَبِيرَة — اليَد اليُمْنَى بَسِ، وَالأَكِل مِن الطَّرَف لِلمَرْكَز."},
      {paraBreak:true,label:"أُمُّ سَمِيرَة وَسِرُّ المَنْسَف"},
      {ar:"أُمُّ سَمِيرَة تَقُومُ الفَجْرَ لِتَطْبُخَ المَنْسَفَ — تَقُولُ: «اللَّحْمُ يَحْتَاجُ سِتَّ سَاعَاتٍ عَلَى نَارٍ هَادِئَة — وَأَنَا أَحْكِي لَهُ طُولَ الوَقْت».",en:"Mother Samira wakes at dawn to cook the mansaf — she says: \"The meat needs six hours on a gentle fire — and I talk to it the whole time.\"",eg:"أُمّ سَمِيرَة بِتِصْحَى الفَجْر تِطْبُخ المَنْسَف — بِتِقُول: «اللَّحْمَة مُحْتَاجَة سِتّ سَاعَات عَلَى نَار هَادِيَة — وَأَنَا بَاتْكَلِّم مَعَاهَا طُول الوَقْت».",lev:"أُمّ سَمِيرَة بِتِصْحَى الفَجْر تِطْبُخ المَنْسَف — بِتِقُول: «اللَّحْمَة لَازِمِتْهَا سِتّ سَاعَات عَالنَّار الهَادِيَة — وَأَنَا بَتْحَكَّى مَعَهَا طُول الوَقْت».",gulf:"أُمّ سَمِيرَة تِصْحَى الفَجْر تِطْبُخ المَنْسَف — تِقُول: «اللَّحْمَة تِحْتَاج سِتّ سَاعَات عَالنَّار الهَادِيَة — وَأَنَا أَتْكَلَّم مَعَهَا طُول الوَقْت»."},
      {ar:"خَالِدٌ يَقُولُ: «كُلَّمَا أَكَلْتُ مَنْسَفَ أُمِّي فِي مَكَانٍ آخَر، أَشْعُرُ أَنَّهُ يَنْقُصُهُ شَيْءٌ — وَأَعْرِفُ أَنَّ هَذَا الشَّيْءَ هُوَ بَيْتُنَا».",en:"Khalid says: \"Whenever I eat mansaf somewhere other than my mother's, I feel it is missing something — and I know that something is our home.\"",eg:"خَالِد بِيِقُول: «كُلَّمَا أَكَلِت مَنْسَف أُمِّي فِي مَكَان تَانِي، بَحِسّ إِنّ فِيه حَاجَة نَاقْصَة — وَعَارِف إِنّ الحَاجَة دِي هِيَّ بَيْتِنَا».",lev:"خَالِد بِيِقُول: «كَلَّمَا أَكَلِت مَنْسَف أُمِّي بِمَكَان تَانِي، بِحِسّ إِنّ فِيه شِي نَاقِص — وَعَارِف إِنّ هَاد الشِي هُوَ بَيْتِنَا».",gulf:"خَالِد يِقُول: «كَلَّمَا أَكَلِت مَنْسَف أُمِّي بِمَكَان تَانِي، أَحِسّ إِنّ فِيه شِي نَاقِص — وَعَارِف إِنّ هَاذَا الشِي هُوَ بَيْتِنَا»."}
      ],
