    dialects:{egy:[{ar:"العَرَبِيَّة لُغَة بِقَوَاعِد دَقِيقَة — الإِعْرَاب مُهِمّ أَوِي.",en:"Arabic is a language with precise rules — grammatical parsing is very important.",eg:"العَرَبِيَّة لُغَة بِقَوَاعِد دَقِيقَة — الإِعْرَاب مُهِمّ أَوِي.",lev:"العَرَبِيَّة لُغَة بِقَوَاعِد دَقِيقَة — الإِعْرَاب مُهِمّ أَوِي.",gulf:"العَرَبِيَّة لُغَة بِقَوَاعِد دَقِيقَة — الإِعْرَاب مُهِمّ أَوِي."},{ar:"الجُمْلَة الاسْمِيَّة مُبْتَدَأ وَخَبَر وَمَفِيشْ فِعْل.",en:"A nominal sentence is subject and predicate with no verb.",eg:"الجُمْلَة الاسْمِيَّة مُبْتَدَأ وَخَبَر وَمَفِيشْ فِعْل.",lev:"الجُمْلَة الاسْمِيَّة مُبْتَدَأ وَخَبَر وَمَفِيشْ فِعْل.",gulf:"الجُمْلَة الاسْمِيَّة مُبْتَدَأ وَخَبَر وَمَفِيشْ فِعْل."},{ar:"التَّطْبِيق عَلَى نُصُوص حَقِيقِيَّة هُوَ الأَحْسَن.",en:"Application on real texts is the best approach.",eg:"التَّطْبِيق عَلَى نُصُوص حَقِيقِيَّة هُوَ الأَحْسَن.",lev:"التَّطْبِيق عَلَى نُصُوص حَقِيقِيَّة هُوَ الأَحْسَن.",gulf:"التَّطْبِيق عَلَى نُصُوص حَقِيقِيَّة هُوَ الأَحْسَن."}],lev:[{ar:"العَرَبِيَّة لُغَة بِقَوَاعِد دَقِيقَة — الإِعْرَاب مُهِمّ كَتِير.",en:"Arabic is a language with precise rules — grammatical parsing is very important.",eg:"العَرَبِيَّة لُغَة بِقَوَاعِد دَقِيقَة — الإِعْرَاب مُهِمّ كَتِير.",lev:"العَرَبِيَّة لُغَة بِقَوَاعِد دَقِيقَة — الإِعْرَاب مُهِمّ كَتِير.",gulf:"العَرَبِيَّة لُغَة بِقَوَاعِد دَقِيقَة — الإِعْرَاب مُهِمّ كَتِير."},{ar:"الجُمْلَة الاسْمِيَّة مُبْتَدَأ وَخَبَر وَمَا فِي فِعْل.",en:"A nominal sentence is subject and predicate with no verb.",eg:"الجُمْلَة الاسْمِيَّة مُبْتَدَأ وَخَبَر وَمَا فِي فِعْل.",lev:"الجُمْلَة الاسْمِيَّة مُبْتَدَأ وَخَبَر وَمَا فِي فِعْل.",gulf:"الجُمْلَة الاسْمِيَّة مُبْتَدَأ وَخَبَر وَمَا فِي فِعْل."},{ar:"التَّطْبِيق عَالنُّصُوص الحَقِيقِيَّة هُوَ الأَحْسَن.",en:"Application on real texts is the best approach.",eg:"التَّطْبِيق عَالنُّصُوص الحَقِيقِيَّة هُوَ الأَحْسَن.",lev:"التَّطْبِيق عَالنُّصُوص الحَقِيقِيَّة هُوَ الأَحْسَن.",gulf:"التَّطْبِيق عَالنُّصُوص الحَقِيقِيَّة هُوَ الأَحْسَن."}],gulf:[{ar:"العَرَبِيَّة لُغَة بِقَوَاعِد دَقِيقَة — الإِعْرَاب وَايِد مُهِمّ.",en:"Arabic is a language with precise rules — grammatical parsing is very important.",eg:"العَرَبِيَّة لُغَة بِقَوَاعِد دَقِيقَة — الإِعْرَاب وَايِد مُهِمّ.",lev:"العَرَبِيَّة لُغَة بِقَوَاعِد دَقِيقَة — الإِعْرَاب وَايِد مُهِمّ.",gulf:"العَرَبِيَّة لُغَة بِقَوَاعِد دَقِيقَة — الإِعْرَاب وَايِد مُهِمّ."},{ar:"الجُمْلَة الاسْمِيَّة مُبْتَدَأ وَخَبَر وَمَا فِيهِ فِعْل.",en:"A nominal sentence is subject and predicate with no verb.",eg:"الجُمْلَة الاسْمِيَّة مُبْتَدَأ وَخَبَر وَمَا فِيهِ فِعْل.",lev:"الجُمْلَة الاسْمِيَّة مُبْتَدَأ وَخَبَر وَمَا فِيهِ فِعْل.",gulf:"الجُمْلَة الاسْمِيَّة مُبْتَدَأ وَخَبَر وَمَا فِيهِ فِعْل."},{ar:"التَّطْبِيق عَلَى نُصُوص حَقِيقِيَّة هُوَ الأَحْسَن.",en:"Application on real texts is the best approach.",eg:"التَّطْبِيق عَلَى نُصُوص حَقِيقِيَّة هُوَ الأَحْسَن.",lev:"التَّطْبِيق عَلَى نُصُوص حَقِيقِيَّة هُوَ الأَحْسَن.",gulf:"التَّطْبِيق عَلَى نُصُوص حَقِيقِيَّة هُوَ الأَحْسَن."}]},
    comprehension:[
  {type:"mcq",q:"Which particle triggers the subjunctive mood?",opts:["لَمْ","هَل","أَن","إِنَّ"],ans:2,exp:"أَن triggers the subjunctive (مَنْصُوب). يُرِيد أَن يَذْهَبَ (he wants to go). The ـُ changes to ـَ. لَمْ triggers jussive. لَن + subjunctive = future negative."},
  {type:"tf",q:"Mohamed Salah is from Alexandria, Egypt.",ans:1,exp:"FALSE — Mohamed Salah was born in Nagrig, a village in Gharbia Governorate, not Alexandria. He is Egypt's most famous modern footballer."},
  {type:"mcq",q:"What is the Arabic for 'championship' or 'tournament'?",opts:["فَرِيق","هَدَف","بُطُولَة","مُبَارَاة"],ans:2,exp:"بُطُولَة = championship/tournament. From بَطَل (hero) → بُطُولَة (heroism → championship). فَرِيق = team. هَدَف = goal. مُبَارَاة = match."},
  {type:"mcq",q:"The passage suggests Arab football generates strong emotions because...",opts:["It is only played by professionals","It connects to national identity and collective pride","It is the most profitable sport","It is only played in summer"],ans:1,exp:"The passage describes how football (كُرَة القَدَم) is not just a sport but a matter of هُوِيَّة وَطَنِيَّة (national identity) and فَخْر جَمَاعِيّ (collective pride) in Arab society."}
,
      {type:"fitb",q:"أُرِيدُ أَنْ _____ الطِّبَّ. (I want to study — subjunctive)",blank:"أَدرُسَ",opts:["أَدرُسَ","أَدرُسُ","دَرَستُ"],exp:"أَنْ triggers the subjunctive: final ـُ → ـَ. أَدرُسُ → أَدرُسَ."},
      {type:"mcq",q:"Which of these triggers the subjunctive mood?",opts:["لَمْ","وَ","أَنْ","لَيسَ"],ans:2,exp:"أَنْ is one of the main subjunctive triggers. Others: لَنْ, كَي, حَتَّى."}],
    grammar:[{
      title:"The Subjunctive — المُضَارِع المَنْصُوب",
      type:"table",
      headers:["Trigger","Meaning","Verb change","Example"],
      rows:[
        ["أَن (an)","to / that","ـُ → ـَ; ـُون → ـُوا","أُرِيد أَن أَفُوزَ"],
        ["لَن (lan)","will not","subjunctive","لَن يَخْسَرَ"],
        ["لِـ (li-)","in order to","subjunctive","يَتَمَرَّن لِيَفُوزَ"],
        ["كَي (kay)","so that","subjunctive","يَرْكُض كَي يَصِلَ"],
        ["حَتَّى","until/so that","subjunctive","يَلْعَب حَتَّى يَنْجَح"]
      ],
      note:"The subjunctive is triggered by أَن and other particles. Singular: final damma → fatha. Sound masculine plural: drops ن. أُرِيد أَن أَكُونَ لَاعِبًا (I want to be a player). ★ SUBJUNCTIVE DRILL: Change these to subjunctive: يَذْهَبُ → أُرِيد أَن ___; يَلْعَبُ → يُحِبّ أَن ___; يَقْرَأُ → يَجِب أَن ___. ★ WORD BANK: لِيَلْعَبَ / لِلَّعِب / يَلْعَب — which fits: جَاءَ ___ مَعَنَا؟"
    }],
