      {ar:"اسْتَشْهَدَ / يَسْتَشْهِد",tr:"istash-hada / yastash-hid",en:"was martyred / becomes a martyr (verb)",eg:"استشهَد / بيِستشهِد",lev:"استشهَد / بيِستشهِد",gulf:"استشهَد / يِستشهِد"},
      {ar:"شَجَاعَة / تَضْحِيَة / صُمُود",tr:"shajaa / tadhhiya / sumuud",en:"courage / sacrifice / steadfastness (nouns)",nuance:"شَجَاعَة = courage (act of facing fear). جُرْأَة = boldness (pushing limits). صُمُود = steadfastness (holding your ground under pressure — specifically Palestinian/Arab resistance vocabulary). تَضْحِيَة = sacrifice (giving something up for a cause).",eg:"شَجاعَة / تَضحِيَة / صُمُود",lev:"شَجاعَة / تَضحِيَة / صُمُود",gulf:"شَجاعَة / تَضحِيَة / صُمُود"},
      {ar:"مُحْتَلّ / مُسْتَعْمِر",tr:"muhtal / mustamir",en:"occupier / coloniser (nouns/adj)",eg:"مُحتَلّ / مُستَعمِر",lev:"مُحتَلّ / مُستَعمِر",gulf:"مُحتَلّ / مُستَعمِر"},
      {ar:"حَتَّى الرَّمَق الأَخِير",tr:"hatta r-ramaqa l-akhiir",en:"until the last breath (literary phrase)",eg:"لحدّ آخِر رَمَق",lev:"لحتَّى آخِر رَمَق",gulf:"لين آخِر رَمَق"},
      {ar:"رَغْمَ / عَلَى الرَّغْم",tr:"raghma / ala r-raghm",en:"despite (preposition / connector)",eg:"رَغم / على الرَّغم",lev:"رَغم / على الرَّغم",gulf:"رَغم / على الرَّغم"}
