      {ar:"يَتَظَاهَر بِـ",tr:"yatazaahar bi",en:"pretends / feigns (verb + prep)",eg:"بيِتظاهَر بِـ",lev:"بيِتظاهَر بِـ",gulf:"يِتظاهَر بِـ"},
      {ar:"ذَكِيّ / بَلِيد",tr:"dhakiyy / baliid",en:"clever / dim (adjectives)",eg:"ذَكِيّ / بَلِيد",lev:"ذَكِيّ / بَلِيد",gulf:"ذَكِيّ / بَلِيد"},
      {ar:"فِي الوَاقِع / عَلَى ظَاهِرِه",tr:"fil-waaqi / ala zaahirih",en:"in reality / on the surface (connectors)",eg:"في الواقِع / على ظاهِرُه",lev:"بالواقِع / على ظاهِرُه",gulf:"بالواقِع / على ظاهِرُه"},
      {ar:"مَثَل أَعْلَى / دَرْس مَسْتَفَاد",tr:"mathal ala / darsa mustafaad",en:"ideal / lesson to be drawn (phrases)",eg:"مَثَل أَعلَى / دَرس مُستَفاد",lev:"مَثَل أَعلَى / دَرس مُستَفاد",gulf:"مَثَل أَعلَى / دَرس مُستَفاد"},
      {ar:"يَضْحَك الجَمِيع",tr:"yadhak al-jamii",en:"everyone laughs (collective verb phrase)",eg:"الكُلّ بيِضحَك",lev:"الكُلّ بيِضحَك",gulf:"الكُلّ يِضحَك"}
