      {ar:"يَسْتَقْبِل / يُوَدِّع",tr:"yastaqbil / yuwaddii",en:"receives (a guest) / bids farewell (verbs)",eg:"بيِستَقبِل / بيِودِّع",lev:"بيِستَقبِل / بيِودِّع",gulf:"يِستَقبِل / يِودِّع"},
      {ar:"تَقْلِيد / عُرْف / عَادَة",tr:"taqliid / urf / aada",en:"tradition / custom / habit (nouns)",eg:"تَقلِيد / عُرف / عادَة",lev:"تَقلِيد / عُرف / عادَة",gulf:"تَقلِيد / عُرف / عادَة"},
      {ar:"كَرِيم / بَخِيل",tr:"kariim / bakhiil",en:"generous / stingy (adjectives)",eg:"كَرِيم / بَخِيل",lev:"كَرِيم / بَخِيل",gulf:"كَرِيم / بَخِيل"},
      {ar:"يَلْتَزِم بِـ",tr:"yaltazim bi",en:"adheres to / commits to (verb + prep)",eg:"بيِلتِزِم بِـ",lev:"بيِلتِزِم بِـ",gulf:"يِلتِزِم بِـ"},
      {ar:"مِن المُعْتَاد أَن",tr:"min al-muutaad an",en:"it is customary to (expression)",eg:"من المُعتاد إِنَّ",lev:"من المُعتاد إِنُّو",gulf:"من المُعتاد إِن"},
      {ar:"بَرَكَة / نِعْمَة",tr:"baraka / niima",en:"blessing / grace (nouns)",eg:"بَرَكَة / نِعمَة",lev:"بَرَكَة / نِعمَة",gulf:"بَرَكَة / نِعمَة"}
