      {ar:"عِلْم / مَعْرِفَة / تَعْلِيم",tr:"ilm / marifa / talim",en:"knowledge / cognition / education (nouns)",eg:"عِلم / مَعرِفَة / تَعلِيم",lev:"عِلم / مَعرِفَة / تَعلِيم",gulf:"عِلم / مَعرِفَة / تَعلِيم"},
      {ar:"مُنْذُ قُرُون",tr:"mundhu quruun",en:"for centuries (prep + time noun)",eg:"مِن قُرُون",lev:"مِن قُرُون",gulf:"مِن قُرُون"},
      {ar:"كَانَ وَلَا يَزَال",tr:"kaana wa-la yazaal",en:"was and still is (kana + negation)",eg:"كَانِ ولِسَّه",lev:"كَانِ ولَسَّا",gulf:"كَانِ ولا زال"}
