      {ar:"مِنَ المَعْلُوم أَنَّ",tr:"min al-maaluuvm anna",en:"it is known that (formal expression)",eg:"من المَعلُوم إِنَّ",lev:"من المَعلُوم إِنُّو",gulf:"من المَعلُوم إِن"},
      {ar:"أَدَّى إِلَى / نَتَجَ عَن",tr:"adda ila / nataja an",en:"led to / resulted from (verbs)",eg:"أَدَّى لِـ / نَتَج عَن",lev:"أَدَّى لِـ / نَتَج عَن",gulf:"أَدَّى لِـ / نَتَج عَن"},
      {ar:"قَرْن (ج) قُرُون",tr:"qarn / quruun",en:"century / centuries (noun + broken plural)",eg:"قَرن / قُرُون",lev:"قَرن / قُرُون",gulf:"قَرن / قُرُون"}
