      {ar:"بَاتَ مَعْرُوفًا", tr:"bāta maʿrūfan", en:"became known (kāna-sister)"},
      {ar:"اعْتَرَفَ / أَنْكَرَ",tr:"iatarafa / ankara",en:"confessed / denied (past verbs)",eg:"اعتَرَف / أَنكَر",lev:"اعتَرَف / أَنكَر",gulf:"اعتَرَف / أَنكَر"},
      {ar:"يُحَقِّق فِي / يَتَحَقَّق مِن",tr:"yuhaqqiq fi / yatahaqqaq min",en:"investigates / verifies (verbs + prep)",eg:"بيِحَقِّق في / بيِتحَقَّق من",lev:"بيِحَقِّق في / بيِتحَقَّق من",gulf:"يِحَقِّق في / يِتحَقَّق من"},
      {ar:"مَجْهُول / مَكْشُوف",tr:"majhuul / makhshuuf",en:"unknown / revealed (passive participles)",eg:"مَجهُول / مَكشُوف",lev:"مَجهُول / مَكشُوف",gulf:"مَجهُول / مَكشُوف"},
      {ar:"بِرَغْم ذَلِك / بِالرَّغْم مِنْهُ",tr:"biraghm dhaalik / bilraghm minhu",en:"despite that / nevertheless (connectors)",eg:"بالرَّغم من كِدَه",lev:"بالرَّغم من هيك",gulf:"بالرَّغم من ذلك"},
      {ar:"فَجْأَة / عَلَى حِين غِرَّة",tr:"fajaan / ala hiin ghirra",en:"suddenly / unexpectedly (adverbs)",eg:"فَجأَة / على حِين غِرَّة",lev:"فَجأَة / على حِين غِرَّة",gulf:"فَجأَة / على حِين غِرَّة"},
      {ar:"لَا شَكَّ أَنَّ",tr:"laa shakka anna",en:"there is no doubt that (expression)",eg:"ما فِيش شَكّ إِنَّ",lev:"ما في شَكّ إِنُّو",gulf:"ما في شَكّ إِن"}
