      {ar:"قِيَادَة / تَوَاصُل / إِبْدَاع",tr:"qiyaada / tawaasul / ibdaa",en:"leadership / communication / creativity (nouns)",eg:"قِيادَة / تَواصُل / إِبداع",lev:"قِيادَة / تَواصُل / إِبداع",gulf:"قِيادَة / تَواصُل / إِبداع"},
      {ar:"بِشَكْل مُسْتَقِلّ / بِرُوح الفَرِيق",tr:"bishakl mustaqill / biruuh al-fariiq",en:"independently / as a team player (phrases)",eg:"بِشَكل مُستَقِلّ / بِرُوح الفَرِيق",lev:"بِشَكل مُستَقِلّ / بِرُوح الفَرِيق",gulf:"بِشَكل مُستَقِلّ / بِرُوح الفَرِيق"},
      {ar:"تَتَوَفَّر / تَتَضَمَّن",tr:"tatawaffar / tatadamman",en:"is available / includes (verbs f)",eg:"بتِتوَفَّر / بتِتضَمَّن",lev:"بتِتوَفَّر / بتِتضَمَّن",gulf:"تِتوَفَّر / تِتضَمَّن"},
      {ar:"أُطَوِّر مَهَارَاتِي",tr:"utawwir mahaardati",en:"I develop my skills (verb phrase — self-motivation)",eg:"بَطَوِّر مَهاراتِي",lev:"عم بَطَوِّر مَهاراتِي",gulf:"أَطَوِّر مَهاراتِي"}
