      {ar:"مِن الطَّبِيعِيّ أَن",tr:"min at-tabiiii an",en:"it is natural that (formal expression)",eg:"من الطَّبِيعِيّ إِنَّ",lev:"من الطَّبِيعِيّ إِنُّو",gulf:"من الطَّبِيعِيّ إِن"}
